import{_ as a,o as t,c as p,ai as _}from"./chunks/framework.B1-4-q7d.js";const i=JSON.parse('{"title":"首届智慧农业创新大赛之对靶施药除草机器人赛道获奖作品","description":"","frontmatter":{"sidebar":false,"aside":false,"editLink":false,"lastUpdated":false,"prev":false,"next":false,"title":"首届智慧农业创新大赛之对靶施药除草机器人赛道获奖作品","date":"2026-03-06T00:00:00.000Z","source":"农业农村部智慧农业-地方实践","category":"cases","link":"https://www.moa.gov.cn/ztzl/zhnyzxd/dfsj/202603/t20260306_6482035.htm","summary":"3WYP-160DB\\n对靶施药除草机器人\\n一、团队介绍\\n合肥多加农业科技有限公司成立于2012年7月,从事智能农机装备研发、生产、销售、服务。主要产品有农业植保机器人、智能播种机、智能施肥机,以及PWM变量喷头、智能喷雾控制系统、风幕系统等多种核心零部件和系统。\\n二、装备亮点\\n3WYP-160DB对靶施药除草机器人\\n一是采用高地隙三轮驱动无人驾驶底盘\\n。\\n动力强劲,操控灵活。\\n二是自主导航作业。...\\n","contentHash":"c0bf3fdfd968e9fe5cb97d9437a6c640","tags":["智慧农业","应用案例"]},"headers":[],"relativePath":"cases/2026-03-06-首届智慧农业创新大赛之对靶施药除草机器人赛道获奖作品.md","filePath":"cases/2026-03-06-首届智慧农业创新大赛之对靶施药除草机器人赛道获奖作品.md"}'),r={name:"cases/2026-03-06-首届智慧农业创新大赛之对靶施药除草机器人赛道获奖作品.md"};function s(n,e,o,l,d,c){return t(),p("div",null,[...e[0]||(e[0]=[_('<h1 id="首届智慧农业创新大赛之对靶施药除草机器人赛道获奖作品" tabindex="-1">首届智慧农业创新大赛之对靶施药除草机器人赛道获奖作品 <a class="header-anchor" href="#首届智慧农业创新大赛之对靶施药除草机器人赛道获奖作品" aria-label="Permalink to &quot;首届智慧农业创新大赛之对靶施药除草机器人赛道获奖作品&quot;">​</a></h1><blockquote><p>来源: <a href="https://www.moa.gov.cn/ztzl/zhnyzxd/dfsj/202603/t20260306_6482035.htm" target="_blank" rel="noreferrer">农业农村部智慧农业-地方实践</a><br> 日期: 2026-03-06 摘要: 3WYP-160DB 对靶施药除草机器人 一、团队介绍 合肥多加农业科技有限公司成立于2012年7月,从事智能农机装备研发、生产、销售、服务。主要产品有农业植保机器人、智能播种机、智能施肥机,以及PWM变量喷头、智能喷雾控制系统、风幕系统等多种核心零部件和系统。 二、装备亮点 3WYP-160DB对靶施药除草机器人 一是采用高地隙三轮驱动无人驾驶底盘 。 动力强劲,操控灵活。 二是自主导航作业。...</p></blockquote><h1 id="_3wyp-160db对靶施药除草机器人" tabindex="-1">3WYP-160DB对靶施药除草机器人 <a class="header-anchor" href="#_3wyp-160db对靶施药除草机器人" aria-label="Permalink to &quot;3WYP-160DB对靶施药除草机器人&quot;">​</a></h1><p>一、团队介绍</p><p>合肥多加农业科技有限公司成立于2012年7月,从事智能农机装备研发、生产、销售、服务。主要产品有农业植保机器人、智能播种机、智能施肥机,以及PWM变量喷头、智能喷雾控制系统、风幕系统等多种核心零部件和系统。</p><p>二、装备亮点</p><p>3WYP-160DB对靶施药除草机器人一是采用高地隙三轮驱动无人驾驶底盘。动力强劲,操控灵活。二是自主导航作业。搭载RTK-GPS实现厘米级定位,适应复杂田块环境。三是杂草精准识别。采用多光谱摄像头与深度学习模型,实时区分作物与杂草。四是对靶变量喷洒。通过电磁阀独立控制每个喷头,仅对杂草位置喷洒除草剂,减少农药使用量。</p><p>三、应用场景与成效</p><p>3WYP-160DB对靶施药除草机器人可广泛应用于玉米、大豆、甜菜及蔬菜等多种作物的精准除草。其核心优势在于通过“对靶变量喷洒”技术,可实现农药使用量降低,并支持全天候作业,极大提升了作业效率与时效性。该机已在山东省潍坊市峡山区及黄河三角洲农业示范区完成苗前除草与苜蓿地除草等实地验证,应用效果表现优异。</p><p>露地蔬菜对靶施药机器人</p><p>北京市农林科学院智能装备技术研究中心精准施药部技术团队,致力于农业智能感知技术与智能装备的研发工作。团队专注于病虫草害检测、作物靶标探测、精准施药控制与无人化作业等领域。</p><p>二、装备亮点</p><p>一是大功率四轮独驱独转线控底盘。采用了先进的线控技术,配备高精度电子控制单元(ECU)和传感器,使车辆具有更高的机动性和敏捷性。机器人搭载的先进定位与导航系统能够在复杂的大田环境中进行高精度的路径规划与定位。二是作物/杂草目标定位方法。采用基于卡尔曼滤波和匈牙利算法的作物/杂草目标定位方法,结合Transformer注意力机制。三是精准喷药和除草。通过自研的高频电磁阀,支持对靶喷药与区域对靶除草两种作业模式。四是系统稳定性。系统配备流量、压力传感器及电动球阀,可实时监控喷药系统的流量和压力,保证喷施过程中流量和压力稳定。</p><p>三、应用场景与成效</p><p>露地蔬菜对靶施药机器人主要应用于甘蓝、西兰花等大株距蔬菜的植保作业,在甘肃张掖和张北等多地进行现场演示。</p><p>NJS-4D4S多功能模块化对靶施药除草机器人</p><p>参赛团队依托农业农村部南京农业机械化研究所创建,核心成员来自植保机械创新团队和棉麻收获技术装备团队,具备跨学科的机械设计、智能控制、计算机视觉和田间应用能力。团队在农业机器人和精准施药领域积累了丰富的研发经验,形成了“方案设计—样机研制—田间试验—迭代优化”的研发模式,为实现自主可控、智能高效的田间作业提供保障。</p><p>二、装备亮点</p><p>一是四轮独立驱动底盘。以自主研发的四轮独立驱动、独立转向农业机器人底盘为核心,具备轮距可调、原地转向、蟹行转向、阿克曼转向等多种运动模式,能够灵活适应不同作物行距和复杂田块条件。二是模块化挂接系统。整机采用模块化挂接系统,支持快速切换对靶施药模块、机械除草模块及常规喷雾模块,实现“一机多用”。</p><p>三、应用场景与成效</p><p>NJS-4D4S多功能模块化对靶施药除草机器人主要用于大田作物、设施蔬菜田间管理,具体包括精准施药、精准施肥、自动除草和作物表型探测等作业。</p><p><a href="https://www.moa.gov.cn/ztzl/zhnyzxd/dfsj/202603/t20260306_6482035.htm" target="_blank" rel="noreferrer">阅读原文</a></p>',22)])])}const h=a(r,[["render",s]]);export{i as __pageData,h as default};
